}
.empty-state-icon { font-size: 2.5rem; margin-bottom: 0.75rem; }
.empty-state h3 { margin: 0 0 0.5rem; font-size: 1.1rem; }
.empty-state p { margin: 0 0 1rem; font-size: 0.9rem; }
```

