## 5. Offline Detection

### Approach
A `useOnlineStatus` hook listens to `navigator.onLine` plus `online`/`offline` window events. When offline, a sticky banner appears and ticket mutations are queued in `localStorage` for replay when connectivity returns.

### Implementation

```tsx
// src/hooks/useOnlineStatus.ts
import { useEffect, useState } from 'react'

export function useOnlineStatus() {
  const [isOnline, setIsOnline] = useState(navigator.onLine)

  useEffect(() => {
    const handleOnline = () => setIsOnline(true)
    const handleOffline = () => setIsOnline(false)

    window.addEventListener('online', handleOnline)
    window.addEventListener('offline', handleOffline)

    return () => {
      window.removeEventListener('online', handleOnline)
      window.removeEventListener('offline', handleOffline)
    }
  }, [])

  return isOnline
}
```

### Offline Banner

```tsx
// src/components/OfflineBanner.tsx
import { useOnlineStatus } from '../hooks/useOnlineStatus'

export function OfflineBanner() {
  const isOnline = useOnlineStatus()

  if (isOnline) return null

  return (
    <div className="offline-banner" role="alert">
      <span>📡</span>
      <span>You're offline. Changes will be saved and synced when you reconnect.</span>
    </div>
  )
}
```

